var SpecialistName = "{!Account.Onboarding_specialist__c}";
var isproject = "{!Account.Onboarding_Account__c}";

if( SpecialistName.length < 5) 
{alert ("Please select an Onboarding Specialist before creating an onboarding project"); 
} 
else

{ 
if( isproject == true )
{alert ("Account already has an onboarding project");

var AccountID = "{!Account.Id}"; 
var SpecialistName = "{!Account.Onboarding_specialist__c}"; 

var url = "/flow/Onboarding_Creation?VarAccountID="+AccountID; 
url= url +"&VarSpecialistName="+SpecialistName+"&retURL=/"+AccountID; 
window.parent.location= url; 
}

else {

var AccountID = "{!Account.Id}"; 
var SpecialistName = "{!Account.Onboarding_specialist__c}"; 


var url = "/flow/Onboarding_Creation?VarAccountID="+AccountID; 
url= url +"&VarSpecialistName="+SpecialistName+"&retURL=/"+AccountID; 



window.parent.location= url; 
}}

